@RestController
public class PetInfoController {

    private final PetDataAccess petDataAccess;

    public PetInfoController(PetDataAccess petDataAccess) {
        this.petDataAccess = petDataAccess;
    }

    @GetMapping("/pets/info")
    @ResponseBody
    public List<PetInfo> getPetsInfo() {
