package org.springframework.samples.petclinic.owner;

import java.time.LocalDateTime;
import java.util.List;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;

@Repository
public interface OwnerRepository extends JpaRepository<Owner, Integer> {

    @Query("SELECT DISTINCT o FROM Owner o LEFT JOIN o.pets p LEFT JOIN p.visits v " +
           "WHERE o.lastModified >= :since OR v.date >= :since ORDER BY o.lastName, o.firstName")
    List<Owner> findOwnersWithRecentActivity(LocalDateTime since);
}

package org.springframework.samples.petclinic.owner;

import java.time.LocalDateTime;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.Table;
import org.springframework.samples.petclinic.model.Person;

@Entity
@Table(name = "owners")
public class Owner extends Person {

    @Column(name = "address")
    private String address;

    @Column(name = "city")
    private String city;

    @Column(name = "telephone")
    private String telephone;

    @Column(name = "last_modified")
    private LocalDateTime lastModified;

    public String getAddress() {
        return address;
    }

    public void setAddress(String address) {
        this.address = address;
    }

    public String getCity() {
        return city;
    }

    public void setCity(String city) {
        this.city = city;
    }

    public String getTelephone() {
        return telephone;
    }

    public void setTelephone(String telephone) {
        this.telephone = telephone;
    }

    public LocalDateTime getLastModified() {
        return lastModified;
    }

    public void setLastModified(LocalDateTime lastModified) {
        this.lastModified = lastModified;
    }
}

package org.springframework.samples.petclinic.owner;

import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.validation.BindingResult;
import org.springframework.web.bind.WebDataBinder;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.InitBinder;
import org.springframework.web.bind.annotation.ModelAttribute;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;

@Controller
public class PetController {

    private final OwnerService ownerService;

    public PetController(OwnerService ownerService) {
        this.ownerService = ownerService;
    }

    @InitBinder
    public void setAllowedFields(WebDataBinder dataBinder) {
        dataBinder.setDisallowedFields("id");
    }

    @ModelAttribute("types")
    public java.util.Collection<PetType> populatePetTypes() {
        return ownerService.getPetTypes();
    }

    @GetMapping("/owners/{ownerId}/pets/new")
    public String initNewPetForm(@PathVariable("ownerId") int ownerId, Model model) {
        Owner owner = ownerService.findOwnerById(ownerId);
        Pet pet = new Pet();
        owner.addPet(pet);
        model.addAttribute("pet", pet);
        model.addAttribute("owner", owner);
        return "pets/createOrUpdatePetForm";
    }

    @PostMapping("/owners/{ownerId}/pets/new")
    public String processNewPetForm(@ModelAttribute("pet") Pet pet, BindingResult result,
            @PathVariable("ownerId") int ownerId) {
        if (result.hasErrors()) {
            return "pets/createOrUpdatePetForm";
        }
        ownerService.savePet(ownerId, pet);
        return "redirect:/owners/{ownerId}";
    }
}

package org.springframework.samples.petclinic.owner;

import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class OwnerService {

    private final OwnerRepository ownerRepository;
    private final PetTypeRepository petTypeRepository;

    public OwnerService(OwnerRepository ownerRepository, PetTypeRepository petTypeRepository) {
        this.ownerRepository = ownerRepository;
        this.petTypeRepository = petTypeRepository;
    }

    public Owner findOwnerById(int ownerId) {
        return ownerRepository.findById(ownerId).orElseThrow(() -> new IllegalArgumentException("Owner not found"));
    }

    public List<PetType> getPetTypes() {
        return petTypeRepository.findPetTypes();
    }

    public void savePet(int ownerId, Pet pet) {
        Owner owner = findOwnerById(ownerId);
        owner.addPet(pet);
        pet.setType(pet.getType());
        ownerRepository.save(owner);
    }
}

package org.springframework.samples.petclinic.owner;

import jakarta.validation.Valid;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.validation.BindingResult;
import org.springframework.web.bind.WebDataBinder;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.InitBinder;
import org.springframework.web.bind.annotation.ModelAttribute;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;

@Controller
public class OwnerController {

    private final OwnerService ownerService;

    public OwnerController(OwnerService ownerService) {
        this.ownerService = ownerService;
    }

    @InitBinder("pet")
    public void initPetBinder(WebDataBinder dataBinder) {
        dataBinder.setValidator(new PetValidator());
    }

    @ModelAttribute("types")
    public java.util.List<PetType> populatePetTypes() {
        return ownerService.getPetTypes();
    }

    @GetMapping("/owners/{ownerId}/pets/new")
    public String initCreationForm(@PathVariable("ownerId") int ownerId, Model model) {
        Owner owner = ownerService.findOwnerById(ownerId);
        Pet pet = new Pet();
        owner.addPet(pet);
        model.addAttribute("pet", pet);
        model.addAttribute("owner", owner);
        return "pets/createOrUpdatePetForm";
    }

    @PostMapping("/owners/{ownerId}/pets/new")
    public String processCreationForm(@PathVariable("ownerId") int ownerId, @Valid Pet pet,
            BindingResult result, Model model) {
        if (result.hasErrors()) {
            Owner owner = ownerService.findOwnerById(ownerId);
            model.addAttribute("owner", owner);
            return "pets/createOrUpdatePetForm";
        }
        ownerService.savePet(ownerId, pet);
        return "redirect:/owners/{ownerId}";
    }
}

