package org.springframework.samples.petclinic.owner;

import java.time.LocalDate;
import java.util.List;
import org.springframework.stereotype.Service;

@Service
public class VaccinationReminderService {

    private final OwnerRepository ownerRepository;

    public VaccinationReminderService(OwnerRepository ownerRepository) {
        this.ownerRepository = ownerRepository;
    }

    public List<VaccinationReminderDto> getUpcomingVaccinationReminders(LocalDate dueDate) {
        LocalDate thresholdDate = dueDate != null ? dueDate : LocalDate.now().plusDays(30);
        return ownerRepository.findAll().stream()
                .flatMap(owner -> owner.getPets().stream()
                        .map(pet -> createReminderDto(owner, pet, thresholdDate)))
                .filter(dto -> dto.nextVaccinationDate() != null && !dto.nextVaccinationDate().isAfter(thresholdDate))
                .toList();
    }

    private VaccinationReminderDto createReminderDto(Owner owner, Pet pet, LocalDate thresholdDate) {
        LocalDate nextVaccinationDate = calculateNextVaccinationDate(pet, thresholdDate);
        return new VaccinationReminderDto(
                owner.getId(),
                owner.getFirstName() + " " + owner.getLastName(),
                pet.getId(),
                pet.getName(),
                nextVaccinationDate
        );
    }

    private LocalDate calculateNextVaccinationDate(Pet pet, LocalDate thresholdDate) {
        return pet.getVisits().stream()
                .map(Visit::getDate)
                .filter(date -> date != null)
                .max(LocalDate::compareTo)
                .map(lastVisitDate -> lastVisitDate.plusDays(365))
                .orElse(null);
    }
}

