package org.springframework.samples.petclinic.owner;

import org.springframework.stereotype.Service;
import java.time.LocalDate;
import java.util.List;
import java.util.stream.Collectors;

@Service
public class VaccinationReminderService {

    private final OwnerRepository ownerRepository;

    public VaccinationReminderService(OwnerRepository ownerRepository) {
        this.ownerRepository = ownerRepository;
    }

    public List<VaccinationReminderDto> getUpcomingVaccinationReminders() {
        return ownerRepository.findAll().stream()
                .flatMap(owner -> owner.getPets().stream()
                        .filter(pet -> needsVaccinationReminder(pet))
                        .map(pet -> new VaccinationReminderDto(
                                owner.getId(),
                                owner.getFirstName() + " " + owner.getLastName(),
                                pet.getId(),
                                pet.getName(),
                                pet.getType().getName(),
                                calculateDaysUntilNextVaccination(pet)
                        )))
                .collect(Collectors.toList());
    }

    public PetVisitHistoryDto getPetVisitHistory(int petId) {
        return ownerRepository.findAll().stream()
                .flatMap(owner -> owner.getPets().stream())
                .filter(pet -> pet.getId().equals(petId))
                .findFirst()
                .map(pet -> new PetVisitHistoryDto(
                        pet.getId(),
                        pet.getName(),
                        pet.getType().getName(),
                        pet.getBirthDate(),
                        pet.getVisits().stream()
                                .map(visit -> new VisitDto(
                                        visit.getDate(),
                                        visit.getDescription()
                                ))
                                .collect(Collectors.toList())
                ))
                .orElse(null);
    }

    public PetDetailsDto getPetDetails(int petId) {
        return ownerRepository.findAll().stream()
                .flatMap(owner -> owner.getPets().stream())
                .filter(pet -> pet.getId().equals(petId))
                .findFirst()
                .map(pet -> new PetDetailsDto(
                        pet.getId(),
                        pet.getName(),
                        pet.getType().getName(),
                        pet.getBirthDate(),
                        ownerRepository.findById(pet.getId())
                                .map(owner -> owner.getFirstName() + " " + owner.getLastName())
                                .orElse("Unknown Owner")
                ))
                .orElse(null);
    }

    public String generateReminderText(int ownerId) {
        return ownerRepository.findById(ownerId)
                .map(owner -> {
                    String petsNeedingVaccination = owner.getPets().stream()
                            .filter(this::needsVaccinationReminder)
                            .map(Pet::getName)
                            .collect(Collectors.joining(", "));
                    return String.format("Уважаемый(ая) %s %s! Напоминаем, что вашим питомцам %s пора сделать вакцинацию.",
                            owner.getFirstName(), owner.getLastName(), petsNeedingVaccination);
                })
                .orElse("");
    }

    private boolean needsVaccinationReminder(Pet pet) {
        return calculateDaysUntilNextVaccination(pet) <= 30;
    }

    private int calculateDaysUntilNextVaccination(Pet pet) {
        LocalDate lastVisitDate = pet.getVisits().stream()
                .map(Visit::getDate)
                .max(LocalDate::compareTo)
                .orElse(pet.getBirthDate());
        LocalDate nextVaccinationDate = lastVisitDate.plusYears(1);
        return (int) LocalDate.now().until(nextVaccinationDate).getDays();
    }
}

