package org.springframework.samples.petclinic.owner;

import java.time.LocalDate;
import java.util.List;
import java.util.stream.Collectors;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;

@Controller
@RequestMapping("/owners/{ownerId}/reminders")
public class VaccinationReminderController {

    private final VaccinationReminderService vaccinationReminderService;
    private final ReminderDtoService reminderDtoService;
    private final PetRepository petRepository;

    public VaccinationReminderController(VaccinationReminderService vaccinationReminderService,
                                        ReminderDtoService reminderDtoService,
                                        PetRepository petRepository) {
        this.vaccinationReminderService = vaccinationReminderService;
        this.reminderDtoService = reminderDtoService;
        this.petRepository = petRepository;
    }

    @GetMapping
    public String showUpcomingReminders(@PathVariable Integer ownerId, Model model) {
        LocalDate now = LocalDate.now();
        LocalDate nextMonth = now.plusMonths(1);

        List<Pet> pets = petRepository.findByOwnerId(ownerId);
        List<ReminderDtoService.ReminderDto> reminders = pets.stream()
            .flatMap(pet -> vaccinationReminderService.getUpcomingReminders(now, nextMonth).stream()
                .filter(reminder -> reminder.getPetId().equals(pet.getId()))
                .map(reminder -> reminderDtoService.toReminderDto(pet, reminder)))
            .collect(Collectors.toList());

        model.addAttribute("reminders", reminders);
        return "owners/remindersList";
    }

    @GetMapping("/pet/{petId}/visits")
    public String showVisitHistory(@PathVariable Integer petId, Model model) {
        Pet pet = petRepository.findById(petId).orElseThrow();
        List<Visit> visits = vaccinationReminderService.getVisitHistoryForPet(petId);
        ReminderDtoService.VisitHistoryDto visitHistory = reminderDtoService.toVisitHistoryDto(pet, visits);
        model.addAttribute("visitHistory", visitHistory);
        return "pets/visitHistory";
    }

    @GetMapping("/pet/{petId}/reminder-text")
    public String generateReminderText(@PathVariable Integer petId, Model model) {
        String reminderText = vaccinationReminderService.generateReminderText(petId);
        model.addAttribute("reminderText", reminderText);
        return "pets/reminderText";
    }
}

