package org.springframework.samples.petclinic.owner;

import org.springframework.stereotype.Service;
import java.util.List;
import java.util.stream.Collectors;
import java.time.LocalDate;

@Service
public class VaccinationService {

    private final VaccinationRepository vaccinationRepository;
    private final PetRepository petRepository;

    public VaccinationService(VaccinationRepository vaccinationRepository, PetRepository petRepository) {
        this.vaccinationRepository = vaccinationRepository;
        this.petRepository = petRepository;
    }

    public List<VaccinationDto> findUpcomingVaccinations() {
        LocalDate today = LocalDate.now();
        LocalDate nextMonth = today.plusMonths(1);

        return vaccinationRepository.findByNextVaccinationDateBetween(today, nextMonth)
            .stream()
            .map(v -> new VaccinationDto(
                v.getId(),
                v.getVaccinationDate(),
                v.getNextVaccinationDate(),
                v.getVaccineType(),
                v.getPet().getId(),
                v.getPet().getName()
            ))
            .collect(Collectors.toList());
    }

    public List<VaccinationDto> findVaccinationHistory(Integer petId) {
        return vaccinationRepository.findByPetId(petId)
            .stream()
            .map(v -> new VaccinationDto(
                v.getId(),
                v.getVaccinationDate(),
                v.getNextVaccinationDate(),
                v.getVaccineType(),
                v.getPet().getId(),
                v.getPet().getName()
            ))
            .collect(Collectors.toList());
    }

    public String generateReminderText(Integer vaccinationId) {
        Vaccination vaccination = vaccinationRepository.findById(vaccinationId)
            .orElseThrow(() -> new IllegalArgumentException("Vaccination not found"));

        return String.format(
            "Напоминание: %s требуется вакцинация %s. Следующая вакцинация назначена на %s.",
            vaccination.getPet().getName(),
            vaccination.getVaccineType(),
            vaccination.getNextVaccinationDate()
        );
    }
}

