import org.springframework.web.bind.annotation.RequestMapping;
import java.util.List;

@Controller
@RequestMapping("/vaccinations")
public class VaccinationController {

    private final VaccinationService vaccinationService;

    public VaccinationController(VaccinationService vaccinationService) {
        this.vaccinationService = vaccinationService;
    }

    @GetMapping("/upcoming")
    public String showUpcomingVaccinations(Model model) {
        List<VaccinationDto> upcomingVaccinations = vaccinationService.findUpcomingVaccinations();
        model.addAttribute("vaccinations", upcomingVaccinations);
        return "vaccinations/upcomingList";
    }

    @GetMapping("/pet/{petId}")
    public String showPetVaccinationHistory(@PathVariable Integer petId, Model model) {
        List<VaccinationDto> history = vaccinationService.findVaccinationHistory(petId);
        model.addAttribute("vaccinations", history);
        return "vaccinations/petHistory";
    }

    @GetMapping("/reminder/{vaccinationId}")
    public String generateReminder(@PathVariable Integer vaccinationId, Model model) {
        String reminderText = vaccinationService.generateReminderText(vaccinationId);
        model.addAttribute("reminderText", reminderText);
        return "vaccinations/reminder";
    }
}

