package org.springframework.samples.petclinic.vet;

import java.time.LocalDate;
import java.util.List;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;

@Repository
public interface VetActivityRepository {

    @Query("SELECT v.firstName as firstName, v.lastName as lastName, COUNT(vi) as visitCount " +
           "FROM Vet v LEFT JOIN v.visits vi " +
           "WHERE vi.date >= :startDate " +
           "GROUP BY v.id, v.firstName, v.lastName " +
           "ORDER BY visitCount DESC")
    List<VetActivityProjection> findVetActivitySince(LocalDate startDate);

    public interface VetActivityProjection {
        String getFirstName();
        String getLastName();
        Long getVisitCount();
    }
}

package org.springframework.samples.petclinic.vet;

import java.time.LocalDate;
import java.util.List;
import java.util.stream.Collectors;
import org.springframework.stereotype.Service;

@Service
public class VetActivityService {

    private final VetActivityRepository vetActivityRepository;

    public VetActivityService(VetActivityRepository vetActivityRepository) {
        this.vetActivityRepository = vetActivityRepository;
    }

    public List<VetActivityDto> getVetActivityReport(int days) {
        LocalDate startDate = LocalDate.now().minusDays(days);
        return vetActivityRepository.findVetActivitySince(startDate)
            .stream()
            .map(p -> new VetActivityDto(p.getFirstName(), p.getLastName(), p.getVisitCount()))
            .collect(Collectors.toList());
    }
}

