package org.springframework.samples.petclinic.vet;

import java.time.LocalDate;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;
import org.springframework.stereotype.Service;

@Service
public class VetActivityService {
    private final VisitRepository visitRepository;

    public VetActivityService(VisitRepository visitRepository) {
        this.visitRepository = visitRepository;
    }

    public List<VetActivityDto> getVetActivityReport(int days) {
        LocalDate startDate = LocalDate.now().minusDays(days);
        return visitRepository.findByDateAfter(startDate)
            .stream()
            .collect(Collectors.groupingBy(
                visit -> visit.getPet().getOwner(),
                Collectors.counting()
            ))
            .entrySet().stream()
            .map(entry -> new VetActivityDto(
                entry.getKey().getFirstName(),
                entry.getKey().getLastName(),
                entry.getValue()
            ))
            .sorted((a, b) -> Long.compare(b.visitCount(), a.visitCount()))
            .toList();
    }
}

