@Repository
public interface VisitRepository extends JpaRepository<Visit, Integer> {
    @Query("SELECT v.vet.id, COUNT(v) as visitCount FROM Visit v WHERE v.date >= :startDate GROUP BY v.vet.id ORDER BY visitCount DESC")
    List<Object[]> countVisitsByVetSince(LocalDate startDate);
}

package org.springframework.samples.petclinic.vet;

import java.time.LocalDate;
import java.time.temporal.ChronoUnit;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;
import org.springframework.samples.petclinic.owner.VisitRepository;
import org.springframework.stereotype.Service;

@Service
public class VetActivityService {
    private final VisitRepository visitRepository;

    public VetActivityService(VisitRepository visitRepository) {
        this.visitRepository = visitRepository;
    }

    public Map<String, Long> getVetActivityReport(int days) {
        LocalDate startDate = LocalDate.now().minus(days, ChronoUnit.DAYS);
        return visitRepository.countVisitsByVetSince(startDate).stream()
                .collect(Collectors.toMap(
                        arr -> ((Number) arr[0]).toString(),
                        arr -> ((Number) arr[1]).longValue()
                ));
    }
}

