package org.springframework.samples.petclinic.system;

import java.time.LocalDate;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.samples.petclinic.service.ClinicDashboardService;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

@Controller
public class ClinicDashboardController {

    private final ClinicDashboardService clinicDashboardService;

    public ClinicDashboardController(ClinicDashboardService clinicDashboardService) {
        this.clinicDashboardService = clinicDashboardService;
    }

    @GetMapping("/dashboard")
    public String showDashboard(Model model) {
        model.addAttribute("ownerCount", clinicDashboardService.countOwners());
        model.addAttribute("petCount", clinicDashboardService.countPets());
        model.addAttribute("visitCount", clinicDashboardService.countVisits());
        model.addAttribute("vetCount", clinicDashboardService.countVets());
        model.addAttribute("recentOwners", clinicDashboardService.findRecentActiveOwners(5));
        model.addAttribute("recentPets", clinicDashboardService.findRecentActivePets(5));
        return "dashboard";
    }

    @GetMapping("/dashboard/metrics")
    public String showMetrics(
            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate start,
            @RequestParam(required = false) @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate end,
            Model model) {
        LocalDate startDate = start != null ? start : LocalDate.now().minusMonths(1);
        LocalDate endDate = end != null ? end : LocalDate.now();

        model.addAttribute("startDate", startDate);
        model.addAttribute("endDate", endDate);
        model.addAttribute("visitCount", clinicDashboardService.countVisitsByPeriod(startDate, endDate));
        model.addAttribute("newOwnerCount", clinicDashboardService.countNewOwnersByPeriod(startDate, endDate));
        model.addAttribute("newPetCount", clinicDashboardService.countNewPetsByPeriod(startDate, endDate));
        return "metrics";
    }
}

package org.springframework.samples.petclinic.service;

import org.springframework.samples.petclinic.owner.Owner;
import org.springframework.samples.petclinic.owner.OwnerRepository;
import org.springframework.samples.petclinic.owner.Pet;
import org.springframework.samples.petclinic.owner.PetRepository;
import org.springframework.samples.petclinic.owner.Visit;
import org.springframework.samples.petclinic.owner.VisitRepository;
import org.springframework.samples.petclinic.vet.Vet;
import org.springframework.samples.petclinic.vet.VetRepository;
import org.springframework.stereotype.Service;

import java.time.LocalDate;
import java.util.List;

@Service
public class ClinicDashboardService {

    private final OwnerRepository ownerRepository;
    private final PetRepository petRepository;
    private final VisitRepository visitRepository;
    private final VetRepository vetRepository;

    public ClinicDashboardService(OwnerRepository ownerRepository, PetRepository petRepository,
                                  VisitRepository visitRepository, VetRepository vetRepository) {
        this.ownerRepository = ownerRepository;
        this.petRepository = petRepository;
        this.visitRepository = visitRepository;
        this.vetRepository = vetRepository;
    }

    public long countOwners() {
        return ownerRepository.count();
    }

    public long countPets() {
        return petRepository.count();
    }

    public long countVisits() {
        return visitRepository.count();
    }

    public long countVets() {
        return vetRepository.findAll().size();
    }

    public List<Owner> findRecentOwners(int limit) {
        return ownerRepository.findAll().stream()
                .sorted((o1, o2) -> o2.getLastName().compareTo(o1.getLastName()))
                .limit(limit)
                .toList();
    }

    public List<Pet> findRecentPets(int limit) {
        return petRepository.findAll().stream()
                .sorted((p1, p2) -> p2.getName().compareTo(p1.getName()))
                .limit(limit)
                .toList();
    }

    public List<Visit> findVisitsByDateRange(LocalDate startDate, LocalDate endDate) {
        return visitRepository.findAll().stream()
                .filter(visit -> !visit.getDate().isBefore(startDate) && !visit.getDate().isAfter(endDate))
                .toList();
    }
}

