package org.springframework.samples.petclinic.owner;

import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.validation.BindingResult;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;

@Controller
@RequestMapping("/owners")
public class FindOwnersController {

    private final OwnerService ownerService;

    public FindOwnersController(OwnerService ownerService) {
        this.ownerService = ownerService;
    }

    @GetMapping("/find")
    public String initFindForm(Model model) {
        model.addAttribute("owner", new Owner());
        return "owners/findOwners";
    }

    @GetMapping("/find")
    public String processFindForm(Owner owner, BindingResult result, Model model, Pageable pageable) {
        if (owner.getLastName() == null) {
            owner.setLastName("");
        }
        model.addAttribute("selectionResults", ownerService.findByLastNameStartingWith(owner.getLastName(), pageable));
        return "owners/findOwners";
    }
}

