package org.springframework.samples.petclinic.owner;

import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;

@Controller
@RequestMapping("/owners")
public class FindOwnersController {

    private final OwnerRepository owners;

    public FindOwnersController(OwnerRepository owners) {
        this.owners = owners;
    }

    @GetMapping("/find")
    public String initFindForm(Model model) {
        model.addAttribute("owner", new Owner());
        return "owners/findOwners";
    }

    @GetMapping("/find")
    public String processFindForm(
            @RequestParam(defaultValue = "1") int page,
            Owner owner,
            Model model) {
        Pageable pageable = Pageable.ofSize(10).withPage(page - 1);
        model.addAttribute("owners", owners.findByLastNameStartingWith(owner.getLastName(), pageable));
        return "owners/ownersList";
    }
}

package org.springframework.samples.petclinic.owner;

import org.springframework.validation.Errors;
import org.springframework.validation.Validator;

public class OwnerValidator implements Validator {

    @Override
    public boolean supports(Class<?> clazz) {
        return Owner.class.isAssignableFrom(clazz);
    }

    @Override
    public void validate(Object target, Errors errors) {
        Owner owner = (Owner) target;
        if (owner.getTelephone() == null || owner.getTelephone().trim().isEmpty()) {
            errors.rejectValue("telephone", "notEmpty", "Telephone must not be empty");
        }
    }

    public boolean validatePhone(Owner owner) {
        return owner.getTelephone() != null && !owner.getTelephone().trim().isEmpty();
    }
}

