package org.springframework.samples.petclinic.owner;

import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

@Controller
public class OwnerController {

    private static final String VIEWS_OWNER_LIST = "owners/ownersList";

    private final OwnerService ownerService;

    public OwnerController(OwnerService ownerService) {
        this.ownerService = ownerService;
    }

    @GetMapping("/owners")
    public String processFindForm(
            @RequestParam(defaultValue = "") String lastName,
            @RequestParam(defaultValue = "1") int page,
            @RequestParam(defaultValue = "10") int size,
            @RequestParam(defaultValue = "lastName,asc") String[] sort,
            Model model) {

        Pageable pageable = org.springframework.data.domain.PageRequest.of(
                page - 1, size,
                org.springframework.data.domain.Sort.by(
                        org.springframework.data.domain.Sort.Direction.fromString(sort[1]),
                        sort[0]));

        Page<Owner> owners = ownerService.findOwnersByLastName(lastName, pageable);
        model.addAttribute("owners", owners);
        model.addAttribute("lastName", lastName);
        return VIEWS_OWNER_LIST;
    }
}

package org.springframework.samples.petclinic.owner;

import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;

@Controller
@RequestMapping("/owners/{ownerId}")
public class OwnerCardController {

    private final OwnerService ownerService;

    public OwnerCardController(OwnerService ownerService) {
        this.ownerService = ownerService;
    }

    @GetMapping
    public String showOwnerCard(@PathVariable Integer ownerId, Model model) {
        ownerService.findOwnerById(ownerId).ifPresent(owner -> {
            model.addAttribute("owner", owner);
            model.addAttribute("pets", owner.getPets());
        });
        return "owners/ownerCard";
    }

    @GetMapping("/pets/new")
    public String initNewPetForm(@PathVariable Integer ownerId, Model model) {
        ownerService.findOwnerById(ownerId).ifPresent(owner -> {
            model.addAttribute("owner", owner);
            model.addAttribute("pet", new Pet());
            model.addAttribute("types", ownerService.getPetTypes());
        });
        return "owners/createOrUpdatePetForm";
    }
}

