        ownerRepository.findById(ownerId).ifPresent(owner -> {
            model.addAttribute("owner", OwnerCardMapper.toDto(owner));
            model.addAttribute("petTypes", petTypeRepository.findPetTypes());
        });
        return "owners/ownerCard";
    }

    @GetMapping("/owners/{ownerId}/pets/new")
    public String initNewPetForm(@PathVariable int ownerId, Model model) {
        ownerRepository.findById(ownerId).ifPresent(owner -> {
            model.addAttribute("owner", owner);
            model.addAttribute("pet", new Pet());
            model.addAttribute("types", petTypeRepository.findPetTypes());
        });
        return "pets/createOrUpdatePetForm";
    }
}

