package org.springframework.samples.petclinic.owner;

import java.util.List;

public record OwnerCardDto(
    Integer id,
    String firstName,
    String lastName,
    String address,
    String city,
    String telephone,
    List<PetCardDto> pets
) {}

package org.springframework.samples.petclinic.owner;

import java.time.LocalDate;

public record PetCardDto(
    Integer id,
    String name,
    LocalDate birthDate,
    String type
) {}

package org.springframework.samples.petclinic.owner;

import org.springframework.samples.petclinic.owner.Owner;
import org.springframework.samples.petclinic.owner.Pet;
import java.util.List;
import java.util.stream.Collectors;

public final class OwnerCardMapper {

    public static OwnerCardDto toDto(Owner owner) {
        if (owner == null) {
            return null;
        }
        List<PetCardDto> petDtos = owner.getPets().stream()
                .map(pet -> new PetCardDto(
                        pet.getId(),
                        pet.getName(),
                        pet.getBirthDate(),
                        pet.getType() != null ? pet.getType().getName() : null
                ))
                .collect(Collectors.toList());

        return new OwnerCardDto(
                owner.getId(),
                owner.getFirstName(),
                owner.getLastName(),
                owner.getAddress(),
                owner.getCity(),
                owner.getTelephone(),
                petDtos
        );
    }
}

package org.springframework.samples.petclinic.owner;

import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Controller;
import org.springframework.ui.ModelMap;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

@Controller
public class OwnerController {

    private final OwnerRepository ownerRepository;

    public OwnerController(OwnerRepository ownerRepository) {
        this.ownerRepository = ownerRepository;
    }

    @GetMapping("/owners")
    public String processFindForm(
            @RequestParam(defaultValue = "1") int page,
            @RequestParam(defaultValue = "10") int size,
            @RequestParam(defaultValue = "lastName,asc") String[] sort,
            @RequestParam(required = false) String lastName,
            ModelMap model) {

        Pageable pageable = org.springframework.data.domain.PageRequest.of(
            page - 1, size,
            org.springframework.data.domain.Sort.by(
                org.springframework.data.domain.Sort.Direction.fromString(sort[1]), sort[0])
        );

        Page<Owner> ownersPage;
        if (lastName == null || lastName.trim().isEmpty()) {
            ownersPage = ownerRepository.findAll(pageable);
        } else {
            ownersPage = ownerRepository.findByLastNameStartingWith(lastName, pageable);
        }

        model.addAttribute("owners", ownersPage.getContent());
        model.addAttribute("page", ownersPage);
        model.addAttribute("lastName", lastName);
        return "owners/ownersList";
    }
}

package org.springframework.samples.petclinic.owner;

import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;
import java.util.Optional;

@Repository
public interface OwnerRepository extends JpaRepository<Owner, Integer> {
    Page<Owner> findByLastNameStartingWith(String lastName, Pageable pageable);
    Page<Owner> findAll(Pageable pageable);
    Optional<Owner> findById(Integer id);
}
